+fn fnv_hash(key: u32) -> u32 {
+    var h = 2166136261u;
+    h ^= (key & 0xFFu); h *= 16777619u;
+    h ^= ((key >> 8u) & 0xFFu); h *= 16777619u;
+    h ^= ((key >> 16u) & 0xFFu); h *= 16777619u;
+    h ^= ((key >> 24u) & 0xFFu); h *= 16777619u;
